(14333, 'c192', '1200000', 'note3a', 245, NULL, 0, '2024-04-26'),
(14334, 'description1', NULL, 'note2', 245, '<p>la comptabilité de notre société est tenue conformément au SYSCOHADA, il est de même des états de synthèse qui en sont issus et  qui sont préparés sur la base d\'une hypothèse de continuité de l\'exploitation.<br><br>Ceci implique:<br>&nbsp; &nbsp; - l\'observance de la convention de prudence<br>&nbsp; &nbsp; - l\'application de bonne foi des règles et procédures en vigueur;<br>&nbsp; &nbsp; - la mise en place par les Responsables des procédures de contrôle interne indispensables<br>&nbsp; &nbsp; - la communication claire des informations sans aucune intention de fraude.<br><br></p>', 0, '0000-00-00'),
(14335, 'description2', NULL, 'note2', 245, '<p>La comptabilité est tenue en Francs CFA selon le système normal<br>Les règles comptables mises en application dans la tenue de la comptabilité portent essentiellement sur les principes fondamentaux regroupés en cinq postulats et cinq conventions qui sont :<br><br>&nbsp; - Postulats :  l\'entité, la comptabilité d\'engagement, la spécialisation des exercices, la permanence des méthodes et la prééminence de la réalité économique sur l\'apparence juridique;<br>&nbsp; - Conventions : le coût historique, la prudence,la régularité et la transparence, la correspondance du bilan de la clôture et du bilan d\'ouverture et l\'importance significative.<br><br></p>', 0, '0000-00-00'),
(14336, 'description3', NULL, 'note2', 245, '<p>Respect de tous les postulats et conventions comptables sans aucune dérogation.<br></p>', 0, '0000-00-00'),
(14337, 'description4', NULL, 'note2', 245, '<p>Pas d\'informations complémentaires relatives aux états financiers.<br></p>', 0, '0000-00-00'),
